const MAIN_WEBHOOK     = 'https://intranet.rajlaxmiworld.com/rest/316/du14lqdt4ijmvzx4';
const ACTIVITY_WEBHOOK = 'https://intranet.rajlaxmiworld.com/rest/71603/jqz6l15bjdnyx803';
const BITRIX_DOMAIN    = 'https://intranet.rajlaxmiworld.com';
const SENDER_NAME      = 'Averlon System';

// ── Optional filters ─────────────────────────────────────────────────────────
const FILTER_PIPELINE_IDS = [];  // CRM Deal Category/Pipeline IDs — empty = all pipelines
const FILTER_USER_IDS     = [];  // Specific user IDs — empty = all users
const FILTER_HOD_IDS      = [];  // HOD user IDs to target — empty = all HODs
// ── CC recipients (always included on every email) ───────────────────────────
const CC_EMAILS           = ['dr.aarti@rajlaxmiworld.com'];
// ────────────────────────────────────────────────────────────────────────────

const IST_OFFSET_MS  = 5.5 * 60 * 60 * 1000;
const nowIST         = new Date(Date.now() + IST_OFFSET_MS);
const todayStr       = nowIST.toISOString().slice(0, 10);

function parseDateStr(str) {
  const [y, m, d] = str.split('-').map(Number);
  return new Date(y, m - 1, d);
}
function parseBitrixDate(dateStr) {
  if (!dateStr) return null;
  const part = new Date(dateStr).toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
  return parseDateStr(part);
}
function formatDate(dateStr) {
  const d = parseBitrixDate(dateStr);
  if (!d) return '\u2014';
  return d.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' });
}

const today          = parseDateStr(todayStr);
const todayTime      = today.getTime();
const windowStart    = new Date(today);
windowStart.setDate(windowStart.getDate() - 30);
const windowStartStr = windowStart.toISOString().slice(0, 10);
const yesterdayStr   = new Date(todayTime - 86400000).toISOString().slice(0, 10);

const CONCURRENCY = 10;

async function fetchAllPages(baseUrl) {
  const results = [];
  let start = 0, hasMore = true;
  const sep = baseUrl.includes('?') ? '&' : '?';
  while (hasMore) {
    const res = await this.helpers.request({
      method: 'GET',
      url: `${baseUrl}${sep}start=${start}`,
      json: true
    });
    const batch = res.result || [];
    results.push(...batch);
    hasMore = !!(res.next && batch.length > 0);
    if (hasMore) start = res.next;
  }
  return results;
}
const fetchAllPagesBound = fetchAllPages.bind(this);

// ── Build deal fetch URL — filter by pipeline if specified ───────────────────
function buildDealUrl() {
  let url = `${ACTIVITY_WEBHOOK}/crm.deal.list.json?filter[CLOSED]=N` +
            `&select[]=ID&select[]=TITLE&select[]=OPPORTUNITY&select[]=CURRENCY_ID&select[]=CATEGORY_ID`;
  if (FILTER_PIPELINE_IDS.length > 0) {
    FILTER_PIPELINE_IDS.forEach((id, i) => {
      url += `&filter[CATEGORY_ID][${i}]=${id}`;
    });
  }
  return url;
}

// ── Parallel bootstrap fetches ───────────────────────────────────────────────
const [deptRes, allUsers, allDeals] = await Promise.all([
  this.helpers.request({ method: 'GET', url: `${MAIN_WEBHOOK}/department.get.json`, json: true }),
  fetchAllPagesBound(`${MAIN_WEBHOOK}/user.get.json?filter[ACTIVE]=true`),
  fetchAllPagesBound(buildDealUrl())
]);

// ── Department map ───────────────────────────────────────────────────────────
const deptMap = new Map();
for (const d of (deptRes.result || [])) {
  deptMap.set(String(d.ID), { name: d.NAME || '', head: d.UF_HEAD ? String(d.UF_HEAD) : null });
}

// ── Deal map — only deals belonging to the filtered pipelines ────────────────
const allowedPipelineSet = new Set(FILTER_PIPELINE_IDS.map(String));
const dealMap = new Map();
for (const d of allDeals) {
  const catId = String(d.CATEGORY_ID ?? '0');
  if (allowedPipelineSet.size > 0 && !allowedPipelineSet.has(catId)) continue;
  dealMap.set(String(d.ID), d);
}

// ── User lookup map ──────────────────────────────────────────────────────────
const userIdToRaw = new Map();
for (const u of allUsers) userIdToRaw.set(String(u.ID), u);

function getEmail(u) {
  if (!u) return '';
  return (Array.isArray(u.EMAIL) ? (u.EMAIL[0]?.VALUE || '') : (u.EMAIL || '')).trim();
}

// ── HOD filter set — if populated, only these HODs will receive emails ────────
const filterHodSet = new Set(FILTER_HOD_IDS.map(String));

// ── Build userMap with optional user filter ──────────────────────────────────
const filterUserSet = new Set(FILTER_USER_IDS.map(String));

const userMap = new Map();
for (const u of allUsers) {
  const uid = String(u.ID);
  if (filterUserSet.size > 0 && !filterUserSet.has(uid)) continue;

  const userDeptIds = Array.isArray(u.UF_DEPARTMENT)
    ? u.UF_DEPARTMENT.map(String).filter(Boolean)
    : (u.UF_DEPARTMENT ? [String(u.UF_DEPARTMENT)] : []);

  let hodId   = null;
  let hodUser = null;
  for (const deptId of userDeptIds) {
    const dept = deptMap.get(deptId);
    if (dept?.head) {
      const candidate = userIdToRaw.get(dept.head);
      if (candidate) { hodId = dept.head; hodUser = candidate; break; }
    }
  }

  // ── If HOD filter is active, skip employees whose HOD is not in the filter ──
  if (filterHodSet.size > 0 && (!hodId || !filterHodSet.has(String(hodId)))) continue;

  userMap.set(uid, {
    id:       uid,
    name:     `${u.NAME || ''} ${u.LAST_NAME || ''}`.trim(),
    email:    getEmail(u),
    hodId,
    hodEmail: getEmail(hodUser),
    hodName:  hodUser ? `${hodUser.NAME} ${hodUser.LAST_NAME}`.trim() : ''
  });
}

// ── Fetch activities per user, keep only those linked to filtered pipeline deals ──
const grouped = new Map();

async function fetchActivitiesForUser(uid) {
  const user = userMap.get(uid);
 // if (!user.hodId || !user.hodEmail) return;

  if (!user.hodId || !user.hodEmail) {
  console.log(`Skipping user ${user.name} — missing HOD email`);
  return;
}


  // ── Skip this user's HOD if not in the HOD filter (double-guard) ─────────
  if (filterHodSet.size > 0 && !filterHodSet.has(String(user.hodId))) return;

  const hodKey = user.hodId;

  const baseUrl =
    `${ACTIVITY_WEBHOOK}/crm.activity.list.json` +
    `?filter[RESPONSIBLE_ID]=${uid}` +
    `&filter[COMPLETED]=N` +
    `&filter[>=DEADLINE]=${windowStartStr}` +
    `&filter[<=DEADLINE]=${yesterdayStr}` +
    `&select[]=ID&select[]=SUBJECT&select[]=DEADLINE&select[]=RESPONSIBLE_ID` +
    `&select[]=TYPE_ID&select[]=OWNER_ID&select[]=OWNER_TYPE_ID`;

  const activities = await fetchAllPagesBound(baseUrl);

  const dealMapUnique = new Map();

  for (const act of activities) {

     const subject = (act.SUBJECT || '').toLowerCase();

  // ❌ Skip "Reason For Loss"
  if (subject.includes('reason for loss')) continue;


   const d = parseBitrixDate(act.DEADLINE);
if (!d) continue;

// ❌ skip future + today
if (d.getTime() >= todayTime) continue;

// ❌ skip older than 30 days
if (d.getTime() < windowStart.getTime()) continue;


    const ownerTypeId = String(act.OWNER_TYPE_ID || '');
    const ownerId     = String(act.OWNER_ID || '');

    if (allowedPipelineSet.size > 0) {
      if (ownerTypeId !== '2') continue;
      if (!dealMap.has(ownerId)) continue;
    }

    const deal   = ownerTypeId === '2' ? dealMap.get(ownerId) : null;
    const daysOv = Math.floor((todayTime - d.getTime()) / 86400000);

    const dealKey = ownerId; // unique deal ID

// ❌ Skip non-deal activities (important)
if (ownerTypeId !== '2') continue;

// ❌ Skip duplicates
if (!dealMapUnique.has(dealKey)) {
  dealMapUnique.set(dealKey, {
    title: deal ? (deal.TITLE || `Deal #${ownerId}`) : (act.SUBJECT || 'No Subject'),
    dueDate: formatDate(act.DEADLINE),
    amount: deal ? `${deal.OPPORTUNITY || 0} ${deal.CURRENCY_ID || ''}`.trim() : '\u2014',
    status: `Overdue by ${daysOv} day(s)`,
    daysOverdue: daysOv,
    url: `${BITRIX_DOMAIN}/crm/deal/details/${ownerId}/`
  });
}
  }
  const deals = Array.from(dealMapUnique.values());


  if (deals.length === 0) return;

  if (!grouped.has(hodKey)) {
    grouped.set(hodKey, {
      hodName:   user.hodName,
      hodEmail:  user.hodEmail,
      employees: new Map()
    });
  }
  grouped.get(hodKey).employees.set(uid, { employee: user, deals });
}

const uids = [...userMap.keys()];
for (let i = 0; i < uids.length; i += CONCURRENCY) {
  await Promise.all(uids.slice(i, i + CONCURRENCY).map(fetchActivitiesForUser));
}

// ── Assemble final output ────────────────────────────────────────────────────
const hodGroups = [];
let totalDeals = 0;

for (const h of grouped.values()) {
  const employees = [...h.employees.values()].filter(e => e.deals.length > 0);
  if (employees.length === 0) continue;
  const dealCount = employees.reduce((s, e) => s + e.deals.length, 0);
  totalDeals += dealCount;

  if (!h.hodEmail) {
  console.log(`Skipping HOD ${h.hodName} — no email`);
  continue;
}

hodGroups.push({
  hodName:   h.hodName,
  hodEmail:  h.hodEmail,
  ccEmails:  CC_EMAILS,
  employees
});
}

return [{
  json: {
    senderName: SENDER_NAME,
    runDate:    todayStr,
    hasDeals:   hodGroups.length > 0,
    hodGroups,
    totalHODs:  hodGroups.length,
    totalDeals,
    ccEmails:   CC_EMAILS           // ← also available at top level for reference
  }
}];

const data = $json;
const { hodGroups, runDate, senderName } = data;

function esc(str = '') {
  return String(str).replace(/[&<>"']/g, s => ({
    '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'
  }[s]));
}

const results = [];

for (const hod of hodGroups) {
  const { hodName, hodEmail, ccEmails = [], employees } = hod;

  const totalEmployees = employees.length;
  const totalDeals     = employees.reduce((s, e) => s + e.deals.length, 0);

  const blocks = employees.map(({ employee, deals }) => {
    const rows = deals.map(d => `
      <tr style="border-bottom:1px solid #f0ede6;">
        <td style="padding:10px 8px;font-size:13px;">${esc(d.title)}</td>
        <td style="padding:10px 8px;font-size:13px;">${esc(d.dueDate)}</td>
        <td style="padding:10px 8px;font-size:13px;">${esc(d.amount)}</td>
        <td style="padding:10px 8px;font-size:12px;color:#A32D2D;font-weight:600;">
          ${esc(d.status)}
        </td>
      </tr>
    `).join('');

    return `
      <div style="margin-bottom:24px;border:1px solid #e0ddd6;border-radius:10px;overflow:hidden;">
        <div style="background:#f7f5f0;padding:12px 20px;">
          <strong>${esc(employee.name)}</strong>
          <span style="margin-left:10px;color:#666;font-size:13px;">${deals.length} overdue deal(s)</span>
        </div>
        <table style="width:100%;border-collapse:collapse;">
          <thead>
            <tr style="background:#faf9f6;border-bottom:2px solid #e0ddd6;">
              <th style="padding:8px;text-align:left;font-size:12px;color:#888;">Deal / Activity</th>
              <th style="padding:8px;text-align:left;font-size:12px;color:#888;">Due Date</th>
              <th style="padding:8px;text-align:left;font-size:12px;color:#888;">Amount</th>
              <th style="padding:8px;text-align:left;font-size:12px;color:#888;">Status</th>
            </tr>
          </thead>
          <tbody>${rows}</tbody>
        </table>
      </div>
    `;
  }).join('');

  const html = `
    <!DOCTYPE html>
    <html>
      <body style="margin:0;padding:0;background:#f4f1eb;font-family:Arial,sans-serif;">
        <div style="max-width:700px;margin:32px auto;background:#fff;border-radius:12px;
                    overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.08);">

          <!-- Header -->
          <div style="background:#1a1a2e;padding:24px 32px;">
            <h2 style="margin:0;color:#fff;font-size:20px;">📋 Overdue Activity Report</h2>
            <p style="margin:4px 0 0;color:#aaa;font-size:13px;">${esc(senderName)} · ${esc(runDate)}</p>
          </div>

          <!-- Greeting -->
          <div style="padding:24px 32px 0;">
            <p style="font-size:15px;margin:0 0 8px;">Hi <strong>${esc(hodName)}</strong>,</p>
            <p style="font-size:14px;color:#444;margin:0 0 24px;">
              Here is your overdue activity summary.
              <strong>${totalEmployees}</strong> team member(s) have
              <strong>${totalDeals}</strong> overdue deal(s) as of <strong>${esc(runDate)}</strong>.
            </p>
          </div>

          <!-- Employee blocks -->
          <div style="padding:0 32px 24px;">
            ${blocks}
          </div>

          <!-- Footer -->
          <div style="background:#f7f5f0;padding:16px 32px;border-top:1px solid #e0ddd6;">
            <p style="margin:0;font-size:12px;color:#999;">
              This is an automated report. Please do not reply to this email.
            </p>
          </div>
        </div>
      </body>
    </html>
  `;

  if (!hodEmail) {
  console.log(`Skipping email for ${hodName} — no email`);
  continue;
}

  results.push({
    json: {
      hodName,
      hodEmail,
      ccEmails,                              // ← passed through for the Send Email node
      ccEmailsString: ccEmails.join(', '),   // ← comma-separated string (some email nodes need this format)
      emailHtml:    html,
      emailSubject: `[Overdue Summary] ${totalDeals} deal(s) across ${totalEmployees} member(s) – ${runDate}`
    }
  });
}

return results;

const { hodName, runDate, senderName, hodEmail } = $json;
const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head><body style="margin:0;padding:0;background:#f4f4f0;font-family:sans-serif;"><div style="max-width:600px;margin:32px auto;background:white;border-radius:12px;padding:32px;border:1px solid #d3d1c7;text-align:center;"><div style="font-size:48px;margin-bottom:16px;">&#10003;</div><h2 style="color:#1a3a2a;margin:0 0 12px;">All Clear!</h2><p style="color:#5f5e5a;">Hi ${hodName}, no overdue deals from yesterday or earlier as of ${runDate}.</p><p style="font-size:12px;color:#888780;margin-top:24px;">Automated morning report from ${senderName}. Do not reply.</p></div></body></html>`;
return [{ json: { hodName, hodEmail, senderName, runDate, emailHtml: html, emailSubject: `[Morning Summary] No Overdue Deals - ${runDate}` } }];

const payload = $json;

const tokenRes = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://login.microsoftonline.com/f284e063-bc3b-44ac-b38c-418c4012e4e8/oauth2/v2.0/token',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: 'grant_type=client_credentials&client_id=e5c42145-d918-4fb3-989d-bcc2093e5a42&client_secret=0xm8Q~WQHXtDZBy2Aitz6U.7Hgm9BRkst2MJOdhr&scope=https%3A%2F%2Fgraph.microsoft.com%2F.default',
});

const token = typeof tokenRes === 'string' ? JSON.parse(tokenRes) : tokenRes;

return {
  json: {
    hodName:      payload.hodName,
    hodEmail:     payload.hodEmail,
    ccEmails:     payload.ccEmails || [],
    senderName:   payload.senderName,
    runDate:      payload.runDate,
    emailHtml:    payload.emailHtml,
    emailSubject: payload.emailSubject,
    access_token: token.access_token
  }
};

